//Copyright(c)HashiCorp,Inc.//SPDX-License-Identifier:MPL-2.0packagebatchimport("strings""testing")funcTestValidName(t*testing.T){t.Parallel()validNames:=[]string{strings.Repeat("W",128),//<=128}for_,v:=rangevalidNames{_,errors:=validName(v,"name")iflen(errors)!=0{t.Fatalf("%qshouldbeavalidBatchname:%q",v,errors)}}invalidNames:=[]string{"s@mple",strings.Repeat("W",129),//>=129}for_,v:=rangeinvalidNames{_,errors:=validName(v,"name")iflen(errors)==0{t.Fatalf("%qshouldbeainvalidBatchname:%q",v,errors)}}}funcTestValidPrefix(t*testing.T){t.Parallel()validPrefixes:=[]string{strings.Repeat("W",102),//<=102}for_,v:=rangevalidPrefixes{_,errors:=validPrefix(v,"prefix")iflen(errors)!=0{t.Fatalf("%qshouldbeavalidBatchprefix:%q",v,errors)}}invalidPrefixes:=[]string{"s@mple",strings.Repeat("W",103),//>=103}for_,v:=rangeinvalidPrefixes{_,errors:=validPrefix(v,"prefix")iflen(errors)==0{t.Fatalf("%qshouldbeainvalidBatchprefix:%q",v,errors)}}}funcTestValidShareIdentifier(t*testing.T){t.Parallel()validShareIdentifiers:=[]string{"sample*","sample1",strings.Repeat("W",255),//<=255,strings.Repeat("W",254)+"*",//optionalasterisk}for_,v:=rangevalidShareIdentifiers{_,errors:=validShareIdentifier(v,"share_identifier")iflen(errors)!=0{t.Fatalf("%qshouldbeavalidshareidentifier:%q",v,errors)}}invalidShareIdentifiers:=[]string{"s@mple",strings.Repeat("W",256),//>255}for_,v:=rangeinvalidShareIdentifiers{_,errors:=validShareIdentifier(v,"share_identifier")iflen(errors)==0{t.Fatalf("%qshouldbeainvalidshareidentifier:%q",v,errors)}}}